module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);


    reg [7:0] cnt;
    reg [1:0] state;
    reg p_red, p_yellow, p_green;

    always@(*) begin
        case(state)
            idle: begin
                p_red = 1'b0;
                p_yellow = 1'b0;
                p_green = 1'b0;

                if(!rst_n) state = idle;
                else state = s1_red;
            end

            s1_red: begin
                p_red = 1'b1;
                p_yellow = 1'b0;
                p_green = 1'b0;

                if(cnt == 3) state = s3_green;
                else state = s1_red;
            end

            s2_yellow: begin
                p_red = 1'b0;
                p_yellow = 1'b1;
                p_green = 1'b0;

                if(cnt == 3) state = s1_red;
                else state = s2_yellow;
            end

            s3_green: begin
                p_red = 1'b0;
                p_yellow = 1'b0;
                p_green = 1'b1;

                if(cnt == 3) state = s2_yellow;
                else state = s3_green;
            end

            default: begin
                p_red = 1'b0;
                p_yellow = 1'b0;
                p_green = 1'b0;

                state = idle;
            end
        endcase
    end

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) cnt <= 10;
        else begin
            if(pass_request && green && (cnt > 10)) cnt <= 10;
            else if(!green && p_green) cnt <= 60;
            else if(!yellow && p_yellow) cnt <= 5;
            else if(!red && p_red) cnt <= 10;
            else cnt <= cnt - 1;
        end
    end

    assign clock = cnt;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            red <= 1'b0;
            yellow <= 1'b0;
            green <= 1'b0;
        end
        else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
endmodule
